sp_widget.client_script:
api.controller = function($rootScope) {
    var c = this;

    // Set Dashboard as the default active tab
    c.activeView = 'dashboard';

    // Function that runs when a menu item is clicked
    c.switchTab = function(viewId) {
        c.activeView = viewId;

        // Shout across the portal that the view has changed!
        $rootScope.$broadcast('tracenow.nav.changed', viewId);
    };
};

sp_widget.css:
.tn-sidebar-widget {
  width: 260px;
  /* Assumes your header is 65px tall, making the sidebar fill the rest of the screen */
  height: calc(100vh - 65px); 
  background: #ffffff;
  border-right: 1px solid #eef2f6;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 24px 16px;
  box-sizing: border-box;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;

  .nav-stack {
    display: flex;
    flex-direction: column;
    gap: 8px;
    
    .nav-tab {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 12px 16px;
      color: #64748b;
      text-decoration: none;
      border-radius: 8px;
      font-weight: 600;
      font-size: 14.5px;
      transition: all 0.2s ease;
      
      .nav-content {
          display: flex;
          align-items: center;
          gap: 12px;
          
          .menu-icon { 
              font-size: 16px;
              width: 20px;
              text-align: center;
          }
      }
      
      /* Hover state for non-active items */
      &:hover:not(.active) { 
          background: #f8fafc; 
          color: #0f172a; 
      }
      
      /* Active state (Dashboard from your picture) */
      &.active {
        background: #0c63e7;
        color: #ffffff;
        box-shadow: 0 4px 6px -1px rgba(12, 99, 231, 0.2);
        
        .chevron { 
            font-size: 12px; 
            opacity: 0.9; 
        }
      }
    }
  }

  /* The bottom icon */
  .sidebar-footer {
    padding: 10px;
    
    .footer-icon-btn {
       width: 40px;
       height: 40px;
       border-radius: 8px;
       background: #f1f5f9;
       color: #64748b;
       display: flex;
       align-items: center;
       justify-content: center;
       cursor: pointer;
       transition: all 0.2s ease;
       
       &:hover {
          background: #e2e8f0;
          color: #0f172a;
       }
    }
  }
}

sp_widget.script:
(function() {
    data.navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: 'fa-th-large' },
        { id: 'connections', label: 'Connections', icon: 'fa-link' },
        { id: 'browse_tables', label: 'Browse Tables', icon: 'fa-database' },
        { id: 'queue', label: 'Queue', icon: 'fa-shopping-cart' },
        { id: 'reports', label: 'Reports', icon: 'fa-bar-chart' },
        { id: 'analytics', label: 'Analytics', icon: 'fa-pie-chart' }
    ];
})();
